command:
// ======================================
// 异常结算样板宏：通过 UUID 施加效果
// ======================================
// 当异常值满槽时自动执行，通过效果物品的 UUID 对目标施加效果。
// 使用方法：复制此宏到宏目录，将下方 EFFECT_UUID 替换为目标效果的 UUID，
//          然后在遗名之穹配置中关联到对应的异常类型。
// 传入参数：{ actor, token, speaker, damageType }
//
// UUID 获取方式：
//   - 在合集包中右键点击物品 → 复制 UUID
//   - 例如：Compendium.pf2e.conditionitems.Item.Giam1GHbXxOxYPqY
//   - 或世界内物品：Item.xxxxxxxxxxxxx
// ======================================

// ===== 用户配置区域 =====
const EFFECT_UUID = "Compendium.pf2e.conditionitems.Item.Giam1GHbXxOxYPqY";  // 要施加的效果物品 UUID
// ===== 配置结束 =====

if (!actor) {
  ui.notifications.warn("异常结算宏：未找到目标角色");
  return;
}

try {
  // 通过 UUID 获取效果物品
  const effectItem = await fromUuid(EFFECT_UUID);
  if (!effectItem) {
    ui.notifications.error(`异常结算宏：无法找到 UUID 对应的物品: ${EFFECT_UUID}`);
    return;
  }

  // 将效果物品转为可嵌入的数据对象
  const effectData = effectItem.toObject();

  // 在角色身上创建该效果
  await actor.createEmbeddedDocuments("Item", [effectData]);

  // 获取伤害类型的本地化名称
  const typeLabel = CONFIG?.PF2E?.damageTypes?.[damageType]
    ? game.i18n.localize(CONFIG.PF2E.damageTypes[damageType])
    : damageType;

  // 发送聊天消息
  const effectName = effectItem.name || "未知效果";
  const effectImg = effectItem.img || "icons/svg/aura.svg";
  const content = `
    <div style="padding: 8px; border-left: 4px solid #0d6efd; background: #f0f6ff; border-radius: 4px;">
      <p style="margin: 0 0 6px; font-weight: bold; color: #0d6efd;">
        <i class="fas fa-magic"></i> 异常结算：施加效果
      </p>
      <p style="margin: 0;">
        <strong>${actor.name}</strong> 的 <strong>${typeLabel}</strong> 异常值已满！
      </p>
      <p style="margin: 4px 0 0; display: flex; align-items: center; gap: 6px;">
        <img src="${effectImg}" style="width: 24px; height: 24px; border: none;" />
        获得效果：<strong>${effectName}</strong>
      </p>
    </div>
  `;
  await ChatMessage.create({ speaker, content });

} catch (err) {
  console.error("异常结算宏执行失败:", err);
  ui.notifications.error("异常结算宏执行失败，请查看控制台");
}
